const htmlOutput = $('Generate HTML Article').first().json.output || '';

// Clean up the HTML output
let cleanHtml = htmlOutput
  .replace(/```html\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

// Fix wpautop-unsafe patterns: ensure SVG+text are on same line
cleanHtml = cleanHtml.replace(/<\/svg>\s*\n\s*/g, '</svg> ');
cleanHtml = cleanHtml.replace(/>\s*\n\s*<svg/g, '><svg');

// Validate basic structure
const hasArticleOpen = cleanHtml.includes('<article');
const hasArticleClose = cleanHtml.includes('</article>');
const hasToc = cleanHtml.includes('תוכן העניינים');
const hasFaq = cleanHtml.includes('שאלות נפוצות');
const hasAuthor = cleanHtml.includes('המכללה האקדמית נתניה');
const hasSchema = cleanHtml.includes('application/ld+json');
const hasFloatingContact = cleanHtml.includes('floating-contact');
const hasBackToTop = cleanHtml.includes('back-to-top');
const hasNoStaleYear = !cleanHtml.match(/עודכן אחרונה:\s*202[0-5]/);

const validation = {
  article_wrapper: hasArticleOpen && hasArticleClose,
  toc_present: hasToc,
  faq_present: hasFaq,
  author_section: hasAuthor,
  json_ld_schemas: hasSchema,
  floating_contact: hasFloatingContact,
  back_to_top: hasBackToTop,
  date_freshness: hasNoStaleYear,
  all_passed: hasArticleOpen && hasArticleClose && hasToc && hasFaq && hasAuthor && hasSchema && hasFloatingContact && hasBackToTop && hasNoStaleYear
};

return [{
  json: {
    html: cleanHtml,
    validation: validation,
    word_count: cleanHtml.split(/\s+/).length,
    char_count: cleanHtml.length
  }
}];

const validation = $('Validate & Clean HTML').first().json.validation;
const failures = Object.entries(validation)
  .filter(([key, val]) => key !== 'all_passed' && val === false)
  .map(([key]) => key);

return [{
  json: {
    error: 'HTML validation failed',
    failed_checks: failures,
    message: `The following mandatory sections are missing: ${failures.join(', ')}. Please regenerate.`
  }
}];
